  // Usuarios y permisos
  "usuarios.aviso": { es: "Esta sección organiza roles y permisos de tu equipo dentro de tu cuenta. Crear inicios de sesión independientes para cada persona (con su propio correo y contraseña) requiere un servidor adicional — por ahora, cada miembro queda registrado con su rol y permisos, pero el acceso al sistema sigue siendo con tu cuenta principal.", en: "This section organizes your team's roles and permissions within your account. Creating independent logins for each person (with their own email and password) requires an additional server — for now, each member is registered with their role and permissions, but system access still goes through your main account.", pt: "Esta seção organiza funções e permissões da sua equipe dentro da sua conta. Criar logins independentes para cada pessoa (com e-mail e senha próprios) requer um servidor adicional — por enquanto, cada membro é registrado com sua função e permissões, mas o acesso ao sistema continua sendo pela sua conta principal.", fr: "Cette section organise les rôles et permissions de votre équipe au sein de votre compte. Créer des connexions indépendantes pour chaque personne (avec son propre e-mail et mot de passe) nécessite un serveur supplémentaire — pour l'instant, chaque membre est enregistré avec son rôle et ses permissions, mais l'accès au système passe toujours par votre compte principal.", de: "Dieser Bereich organisiert Rollen und Rechte deines Teams innerhalb deines Kontos. Unabhängige Logins für jede Person (mit eigener E-Mail und Passwort) erfordern einen zusätzlichen Server — vorerst wird jedes Mitglied mit Rolle und Rechten erfasst, der Systemzugriff erfolgt aber weiterhin über dein Hauptkonto.", zh: "此部分用于管理您账户内团队的角色和权限。为每个人创建独立登录（拥有各自的邮箱和密码）需要额外的服务器 — 目前，每位成员都会记录其角色和权限，但系统访问仍通过您的主账户进行。" },
  "usuarios.cambiar_contrasena": { es: "Cambiar mi contraseña", en: "Change my password", pt: "Alterar minha senha", fr: "Changer mon mot de passe", de: "Mein Passwort ändern", zh: "修改我的密码" },
  "usuarios.cambiar_contrasena_desc": { es: "Esto cambia la contraseña de tu propia cuenta.", en: "This changes your own account's password.", pt: "Isso altera a senha da sua própria conta.", fr: "Cela change le mot de passe de votre propre compte.", de: "Dies ändert das Passwort deines eigenen Kontos.", zh: "这将更改您自己账户的密码。" },
  "usuarios.nueva_contrasena": { es: "Nueva contraseña", en: "New password", pt: "Nova senha", fr: "Nouveau mot de passe", de: "Neues Passwort", zh: "新密码" },
  "usuarios.confirmar_contrasena": { es: "Confirmar contraseña", en: "Confirm password", pt: "Confirmar senha", fr: "Confirmer le mot de passe", de: "Passwort bestätigen", zh: "确认密码" },
  "usuarios.actualizar_contrasena": { es: "Actualizar contraseña", en: "Update password", pt: "Atualizar senha", fr: "Mettre à jour le mot de passe", de: "Passwort aktualisieren", zh: "更新密码" },
